return $input.all().map((item) => {
  const source = item.json;

  return {
    json: {
      questionId: source.questionId,
      status: "pending_review",

      targetCollectionPath: source.collectionPath,
      targetLevelDocumentPath: source.levelDocumentPath,

      documentData: source.documentData,
      previewText: source.previewText,

      telegramChatId: source.telegramChatId,
      originalTelegramMessageId: source.originalTelegramMessageId,

      provenance: source.documentData?.provenance || null,
      generationOptions: source.generationOptions || null,

      createdAt: source.createdAt || new Date().toISOString(),
      updatedAt: new Date().toISOString()
    }
  };
});

const input = $input.first().json;
const callback = input.callback_query;

if (!callback) {
  return [
    {
      json: {
        validCallback: false,
        error: "Це не callback query.",
        responseText: "❌ Це не callback query.",
        debugInput: input
      }
    }
  ];
}

const data = String(callback.data || "").replace(/^=/, "");
const [action, questionId] = data.split("|");

const allowedActions = ["approve", "revise", "reject"];

const chatId =
  callback.message?.chat?.id ||
  callback.from?.id ||
  59229320;

if (!allowedActions.includes(action)) {
  return [
    {
      json: {
        validCallback: false,
        error: `Невідома дія: ${action}`,
        callbackData: data,
        callbackQueryId: callback.id,
        telegramChatId: String(chatId),
        responseText: `❌ Невідома дія: ${action}`
      }
    }
  ];
}

if (!questionId) {
  return [
    {
      json: {
        validCallback: false,
        error: "Не передано questionId у callback data.",
        callbackData: data,
        callbackQueryId: callback.id,
        telegramChatId: String(chatId),
        responseText: "❌ Не передано ID питання."
      }
    }
  ];
}

const actionLabels = {
  approve: "✅ Обрано дію: записати питання в БД.",
  revise: "✏️ Обрано дію: переробити питання.",
  reject: "❌ Обрано дію: відхилити питання."
};

return [
  {
    json: {
      validCallback: true,
      action,
      questionId,
      callbackQueryId: callback.id,
      telegramChatId: String(chatId),
      telegramMessageId: callback.message?.message_id,
      telegramFromId: callback.from?.id,
      callbackData: data,
      responseText: `${actionLabels[action]}\n\nID питання:\n${questionId}`
    }
  }
];

function fail(message, errorType = "validation_error") {
  const input = $input.item?.json || {};

  return [
    {
      json: {
        valid: false,
        error: message,
        errorType,
        telegramChatId: input.message?.chat?.id || input.telegramChatId || null,
        telegramFromId: input.message?.from?.id || input.telegramFromId || null,
        originalTelegramMessageId: input.message?.message_id || input.originalTelegramMessageId || null,
        generationOptions: input.generationOptions || null
      },
    },
  ];
}

function slugify(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .replace(/ї/g, "i")
    .replace(/і/g, "i")
    .replace(/є/g, "e")
    .replace(/ґ/g, "g")
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 60);
}

function randomId(length = 4) {
  const chars = "abcdefghijklmnopqrstuvwxyz0123456789";
  let result = "";

  for (let i = 0; i < length; i++) {
    result += chars[Math.floor(Math.random() * chars.length)];
  }

  return result;
}

function formatAnswerPreview(data) {
  if (Array.isArray(data.answers)) {
    return data.answers
      .map((answer, index) => {
        const isCorrect = Array.isArray(data.correctAnswerIndices)
          && data.correctAnswerIndices.includes(index);

        return `${index + 1}. ${answer}${isCorrect ? " ✅" : ""}`;
      })
      .join("\n");
  }

  if (data.type === "TRUE_FALSE") {
    return `Правильна відповідь: ${data.correctAnswer ? "Так" : "Ні"}`;
  }

  if (Array.isArray(data.correctAnswers)) {
    return `Правильні відповіді: ${data.correctAnswers.join(", ")}`;
  }

  if (data.type === "MATCHING") {
    return [
      "Ліва сторона:",
      ...(data.leftSide || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Права сторона:",
      ...(data.rightSide || []).map((x, i) => `${i + 1}. ${x}`),
    ].join("\n");
  }

  if (data.type === "COMPARISON") {
    return [
      "Категорії:",
      ...(data.categories || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Твердження:",
      ...(data.statements || []).map((x, i) => `${i + 1}. ${x.text}`),
    ].join("\n");
  }

  return "Для цього типу питання короткий preview ще не налаштований.";
}

const input = $input.item.json;
const messageText = input.message?.text;

if (!messageText) {
  return fail("Повідомлення Telegram не містить тексту.");
}

if (messageText.startsWith("/")) {
  return fail("Це службова команда Telegram, а не JSON питання.");
}

let payload;

try {
  payload = JSON.parse(messageText);
} catch (error) {
  return fail("Повідомлення не є валідним JSON. Перевір лапки, коми та дужки.");
}

const allowedCategories = [
  "erudite",
  "science",
  "philosophy",
  "culture",
  "noesis",
  "agora",
];

const allowedTypes = [
  "SINGLE_CHOICE",
  "MULTIPLE_CHOICE",
  "TRUE_FALSE",
  "SEQUENCE",
  "MATCHING",
  "COMPARISON",
  "TEXT_INPUT",
  "FILL_IN_THE_BLANK",
  "IMAGE_CHOICE",
  "READING_COMPREHENSION",
  "SLIDER_SCALE",
  "TEN_FACTS",
];

const categoryId = payload.categoryId || input.generationOptions?.categoryId;
const levelId = String(payload.levelId || input.generationOptions?.levelId || "");
const rawNum = payload.num ?? input.generationOptions?.num ?? 1;
const num = Number(rawNum);
const block = String(payload.block || input.generationOptions?.block || "").toUpperCase();
const rawSlug = payload.slug;
const data = payload.data;


if (!allowedCategories.includes(categoryId)) {
  return fail("Невалідний categoryId. Дозволено: erudite, science, philosophy, culture, noesis, agora.");
}

if (!levelId) {
  return fail("Відсутнє поле levelId.");
}

if (!Number.isInteger(num) || num < 1 || num > 999) {
  return fail("Поле num має бути цілим числом від 1 до 999.");
}

if (!/^[A-Z]$/.test(block)) {
  return fail("Поле block має бути однією великою літерою: A, B, C тощо.");
}

if (!data || typeof data !== "object") {
  return fail("Відсутній об'єкт data.");
}

if (data.lang !== "ua") {
  return fail("Поле data.lang має бути ua.");
}

if (!allowedTypes.includes(data.type)) {
  return fail("Невалідний type. Тип питання має бути написаний ВЕРХНІМ РЕГІСТРОМ.");
}

if (!Array.isArray(data.topics) || data.topics.length === 0) {
  return fail("Поле data.topics є обов'язковим і має бути непорожнім масивом.");
}

if (!data.question && !["READING_COMPREHENSION", "SLIDER_SCALE"].includes(data.type)) {
  return fail("Поле data.question є обов'язковим для цього типу питання.");
}

if (data.provenance && typeof data.provenance !== "object") {
  return fail("Поле data.provenance має бути об'єктом.");
}

if (data.provenance?.sourceIds && !Array.isArray(data.provenance.sourceIds)) {
  return fail("Поле data.provenance.sourceIds має бути масивом.");
}

if (Array.isArray(data.correctAnswerIndices)) {
  data.correctAnswerIndices = data.correctAnswerIndices.map(Number);
}

switch (data.type) {
  case "SINGLE_CHOICE":
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail("SINGLE_CHOICE повинен мати рівно 6 варіантів answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== 1) {
      return fail("SINGLE_CHOICE повинен мати один правильний індекс у correctAnswerIndices.");
    }
    break;

  case "MULTIPLE_CHOICE":
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail("MULTIPLE_CHOICE повинен мати рівно 6 варіантів answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length < 2) {
      return fail("MULTIPLE_CHOICE повинен мати щонайменше два правильні індекси.");
    }
    break;

  case "TRUE_FALSE":
    if (typeof data.correctAnswer !== "boolean") {
      return fail("TRUE_FALSE повинен мати correctAnswer типу boolean: true або false.");
    }
    break;

  case "SEQUENCE":
    if (!Array.isArray(data.answers) || data.answers.length < 4 || data.answers.length > 6) {
      return fail("SEQUENCE повинен мати від 4 до 6 елементів answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== data.answers.length) {
      return fail("SEQUENCE повинен мати correctAnswerIndices тієї самої довжини, що й answers.");
    }
    break;

  case "MATCHING":
    if (!Array.isArray(data.leftSide) || !Array.isArray(data.rightSide) || !Array.isArray(data.correctMatches)) {
      return fail("MATCHING повинен мати leftSide, rightSide і correctMatches.");
    }
    break;

  case "COMPARISON":
    if (!Array.isArray(data.categories) || !Array.isArray(data.statements)) {
      return fail("COMPARISON повинен мати categories і statements.");
    }
    break;

  case "TEXT_INPUT":
  case "FILL_IN_THE_BLANK":
    if (!Array.isArray(data.correctAnswers) || data.correctAnswers.length === 0) {
      return fail(`${data.type} повинен мати correctAnswers.`);
    }
    break;

  case "IMAGE_CHOICE":
    if (!Array.isArray(data.answers) || !Array.isArray(data.correctAnswerIndices)) {
      return fail("IMAGE_CHOICE повинен мати answers і correctAnswerIndices.");
    }
    break;

  case "READING_COMPREHENSION":
    if (!data.text1 || !data.text2 || !Array.isArray(data.questions)) {
      return fail("READING_COMPREHENSION повинен мати text1, text2 і questions.");
    }
    break;

  case "SLIDER_SCALE":
    if (!data.text || !Array.isArray(data.sliders)) {
      return fail("SLIDER_SCALE повинен мати text і sliders.");
    }
    break;

  case "TEN_FACTS":
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail("TEN_FACTS повинен мати рівно 6 варіантів answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== 1) {
      return fail("TEN_FACTS повинен мати один правильний індекс.");
    }

    if (!Array.isArray(data.facts) || data.facts.length === 0) {
      return fail("TEN_FACTS повинен мати facts.");
    }
    break;
}

const numPart = String(num).padStart(2, "0");
const slug = slugify(rawSlug || data.question || data.type);
const questionId = `${data.lang}--${numPart}--${block}--${slug}--${randomId()}`;
const now = new Date().toISOString();

const documentData = {
  ...data,
  categoryId,
  levelId,
  questionId,
  num,
  block,
  slug,
  status: "pending_review",
  source: "telegram-n8n",
  createdAt: now,
  updatedAt: now,
};

const generationOptions = input.generationOptions || {};
const sourceQualityText = generationOptions.researchEnabled
  ? [
      `Якість джерел: ${generationOptions.sourceBriefQuality || "unknown"}`,
      `Source confidence: ${generationOptions.sourceConfidence ?? "unknown"}`,
      generationOptions.sourceSufficiency?.reason
        ? `Source sufficiency: ${generationOptions.sourceSufficiency.reason}`
        : null
    ].filter(Boolean).join("\n")
  : null;

const previewText = [
  "🧠 Нове питання на модерацію",
  "",
  `Категорія: ${categoryId}`,
  `Рівень: ${levelId}`,
  `Блок: ${block}`,
  `Тип: ${data.type}`,
  `ID: ${questionId}`,
  `Теми: ${data.topics.join(", ")}`,
  sourceQualityText,
  "",
  "Питання:",
  data.question || data.text || "Без короткого тексту питання",
  "",
  "Варіанти / відповідь:",
  formatAnswerPreview(data),
  "",
  data.explanation ? `Пояснення:\n${data.explanation}` : "Пояснення: не додано",
  "",
  data.provenance?.sourceIds?.length
    ? `Джерела:\n${data.provenance.sourceIds.join("\n")}`
    : null,
  "",
  "Дія:",
  "✅ записати в БД",
  "❌ відхилити",
  "✏️ переробити",
].filter(Boolean).join("\n");

return [
  {
    json: {
      valid: true,
      categoryId,
      levelId,
      questionId,
      collectionPath: `${categoryId}/${levelId}/questions`,
      levelDocumentPath: `${categoryId}/${levelId}`,
      pendingCollectionPath: "pendingQuestions",
      documentData,
      previewText,
      telegramChatId: input.message.chat.id,
      telegramFromId: input.message.from.id,
      originalTelegramMessageId: input.message.message_id,

      generationOptions: input.generationOptions || null
    },
  },
];

const text = String($json.message?.text || "").trim();

function getParam(name, defaultValue = "") {
  const quoted = text.match(new RegExp(`${name}="([^"]+)"`, "i"));
  if (quoted) return quoted[1].trim();

  const simple = text.match(new RegExp(`${name}=([^\\s]+)`, "i"));
  if (simple) return simple[1].trim();

  return defaultValue;
}

const mode = text.startsWith("/generate_quiz")
  ? "quiz"
  : text.startsWith("/generate_question")
    ? "question"
    : "unknown";

if (mode === "unknown") {
  return [
    {
      json: {
        ok: false,
        error: "Невідома команда. Використай /generate_question або /generate_quiz.",
        telegramChatId: $json.message.chat.id
      }
    }
  ];
}

const topic = getParam("topic", "");
const categoryId = getParam("categoryId", "erudite");
const levelId = getParam("levelId", "1");
const block = getParam("block", "A").toUpperCase();
const type = getParam("type", "SINGLE_CHOICE").toUpperCase();

let requestedCount = Number(getParam("count", mode === "quiz" ? "5" : "1"));

if (!Number.isFinite(requestedCount) || requestedCount < 1) {
  requestedCount = mode === "quiz" ? 5 : 1;
}

const maxQuizCount = 10;

let count = requestedCount;

if (mode === "question") {
  count = 1;
}

if (mode === "quiz" && count > maxQuizCount) {
  count = maxQuizCount;
}

const saveToDb = /(?:^|\s)db=on(?:\s|$)/i.test(text);
const sendDocument = !/(?:^|\s)doc=off(?:\s|$)/i.test(text);

const format = getParam("format", "markdown").toLowerCase();

const reviewEnabled = ["on", "true", "1", "yes"].includes(
  String(getParam("review", "off")).toLowerCase()
);

const autoReview = !["off", "false", "0", "no"].includes(
  String(getParam("autoReview", "on")).toLowerCase()
);

const reviewReason = null;

const researchEnabled = ["on", "true", "1", "yes"].includes(
  String(getParam("research", "off")).toLowerCase()
);

const deepResearch = ["on", "true", "1", "yes"].includes(
  String(getParam("deep", "off")).toLowerCase()
);

let sourceLimit = Number(getParam("sources", "3"));

if (!Number.isFinite(sourceLimit) || sourceLimit < 1) {
  sourceLimit = 3;
}

sourceLimit = Math.min(sourceLimit, 5);

const researchProvider = getParam("provider", "openalex").toLowerCase();

if (!topic) {
  return [
    {
      json: {
        ok: false,
        error: "Не вказано topic. Приклад: /generate_question topic=\"Іван Котляревський\" db=off doc=on",
        telegramChatId: $json.message.chat.id
      }
    }
  ];
}

return [
  {
    json: {
      ok: true,
      mode,
      topic,
      categoryId,
      levelId,
      block,
      type,
      count,
      requestedCount,
      maxQuizCount,
      countWasLimited: mode === "quiz" && requestedCount > maxQuizCount,
      saveToDb,
      sendDocument,
      format,
      researchEnabled,
      reviewEnabled,
      autoReview,
      reviewReason,
      deepResearch,
      sourceLimit,
      researchProvider,
      originalCommand: text,
      telegramChatId: $json.message.chat.id,
      telegramFromId: $json.message.from.id,
      originalTelegramMessageId: $json.message.message_id
    }
  }
];

const input = $input.first().json;

const aiText =
  input.output_text ||
  input.output?.[0]?.content?.[0]?.text ||
  input.output?.[0]?.content?.find?.(c => c.type === "output_text")?.text ||
  input.text ||
  "";

if (!aiText) {
  return [
    {
      json: {
        message: { text: "" },
        aiError: "OpenAI не повернув текст у відомому полі.",
        raw: input
      }
    }
  ];
}

const cleaned = String(aiText)
  .trim()
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```$/i, "")
  .trim();

const parseOptions = $("Parse Generate Options").item.json;

let sourceContext = {};

try {
  if ($("Decide Source Sufficiency").isExecuted) {
    sourceContext = $("Decide Source Sufficiency").item.json;
  } else if ($("Build Source Brief").isExecuted) {
    sourceContext = $("Build Source Brief").item.json;
  }
} catch (error) {
  sourceContext = {};
}

return [
  {
    json: {
      message: {
        text: cleaned,
        chat: {
          id: parseOptions.telegramChatId
        },
        from: {
          id: parseOptions.telegramFromId
        },
        message_id: parseOptions.originalTelegramMessageId
      },
      generationOptions: {
        saveToDb: parseOptions.saveToDb,
        sendDocument: parseOptions.sendDocument,
        format: parseOptions.format,
        mode: parseOptions.mode,
        topic: parseOptions.topic,
        categoryId: parseOptions.categoryId,
        levelId: parseOptions.levelId,
        block: parseOptions.block,
        type: parseOptions.type,
        researchEnabled: parseOptions.researchEnabled,
        reviewEnabled: parseOptions.reviewEnabled,
        autoReview: parseOptions.autoReview,

        sourceBriefQuality: sourceContext.sourceBriefQuality || null,
        sourceBriefStatus: sourceContext.sourceBriefStatus || null,
        sourceConfidence: sourceContext.sourceConfidence ?? null,
        sourceAuthoritySummary: sourceContext.sourceAuthoritySummary || null,
        sourcePolicy: sourceContext.sourcePolicy || null,
        sourceSufficiency: sourceContext.sourceSufficiency || null,
        researchProvider: sourceContext.researchProvider || parseOptions.researchProvider || null,
        sourceCount: Array.isArray(sourceContext.retrievedSources)
          ? sourceContext.retrievedSources.length
          : 0
      }
    }
  }
];

function safeFileName(value) {
  return String(value || "noesis_question")
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 80);
}

const input = $input.first().json;
const data = input.documentData;

if (!data) {
  return [
    {
      json: {
        ok: false,
        error: "Немає documentData для формування документа."
      }
    }
  ];
}

let markdown = "";

markdown += `# NoesisQuiz: питання\n\n`;
markdown += `**Тема генерації:** ${input.generationOptions?.topic || "не вказано"}\n\n`;
markdown += `**Категорія:** ${input.categoryId}\n\n`;
markdown += `**Рівень:** ${input.levelId}\n\n`;
markdown += `**Блок:** ${data.block || input.block || "A"}\n\n`;
markdown += `**Тип:** ${data.type}\n\n`;
markdown += `**ID:** ${input.questionId}\n\n`;

markdown += `## Питання\n\n`;
markdown += `${data.question || data.text || "Без тексту питання"}\n\n`;

if (Array.isArray(data.answers)) {
  markdown += `## Варіанти відповіді\n\n`;

  data.answers.forEach((answer, index) => {
    const isCorrect =
      Array.isArray(data.correctAnswerIndices) &&
      data.correctAnswerIndices.includes(index);

    markdown += `${index + 1}. ${answer}${isCorrect ? " ✅" : ""}\n`;
  });

  markdown += `\n`;
}

if (typeof data.correctAnswer === "boolean") {
  markdown += `## Правильна відповідь\n\n`;
  markdown += `${data.correctAnswer ? "Так" : "Ні"}\n\n`;
}

if (Array.isArray(data.correctAnswers)) {
  markdown += `## Правильні відповіді\n\n`;
  markdown += `${data.correctAnswers.join(", ")}\n\n`;
}

if (data.explanation) {
  markdown += `## Пояснення\n\n`;
  markdown += `${data.explanation}\n\n`;
}

if (Array.isArray(data.topics)) {
  markdown += `## Теми\n\n`;
  markdown += `${data.topics.join(", ")}\n\n`;
}

if (Array.isArray(data.scientificDisciplines)) {
  markdown += `## Дисципліни\n\n`;
  markdown += `${data.scientificDisciplines.join(", ")}\n\n`;
}

if (Array.isArray(data.recommendedLiterature) && data.recommendedLiterature.length > 0) {
  markdown += `## Рекомендована література\n\n`;

  data.recommendedLiterature.forEach((item) => {
    markdown += `- ${item.name || "Джерело"}${item.link ? ` - ${item.link}` : ""}\n`;
  });

  markdown += `\n`;
}

markdown += `---\n\n`;
markdown += `JSON ID: \`${input.questionId}\`\n`;
markdown += `Створено: ${new Date().toISOString()}\n`;

const fileName = `${safeFileName(input.generationOptions?.topic || data.slug || input.questionId)}.md`;

return [
  {
    json: {
      ...input,
      ok: true,
      fileName,
      documentText: markdown
    },
    binary: {
      data: {
        data: Buffer.from(markdown, "utf8").toString("base64"),
        mimeType: "text/markdown",
        fileName
      }
    }
  }
];

function safeFileName(value) {
  return String(value || "noesis_quiz")
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 80);
}

const input = $input.first().json;
const raw = input.message?.text || "";

let quiz;

try {
  quiz = JSON.parse(raw);
} catch (error) {
  return [
    {
      json: {
        ok: false,
        error: "AI повернув невалідний JSON для міні-вікторини.",
        raw
      }
    }
  ];
}

const questions = Array.isArray(quiz.questions) ? quiz.questions : [];

let markdown = `# ${quiz.quizTitle || "NoesisQuiz: міні-вікторина"}\n\n`;
markdown += `**Тема:** ${quiz.topic || $("Parse Generate Options").item.json.topic}\n\n`;
markdown += `**Категорія:** ${quiz.categoryId || $("Parse Generate Options").item.json.categoryId}\n\n`;
markdown += `**Рівень:** ${quiz.levelId || $("Parse Generate Options").item.json.levelId}\n\n`;
markdown += `**Блок:** ${quiz.block || $("Parse Generate Options").item.json.block}\n\n`;
markdown += `**Кількість питань:** ${questions.length}\n\n`;
markdown += `---\n\n`;

const options = $("Parse Generate Options").item.json;

if (options.countWasLimited) {
  markdown += `> ⚠️ Запитану кількість питань зменшено з ${options.requestedCount} до ${options.maxQuizCount}, щоб уникнути надмірної генерації.\n\n`;
}

questions.forEach((q, index) => {
  const data = q.data || q;

  markdown += `## ${index + 1}. ${data.question || "Питання без тексту"}\n\n`;
  markdown += `**Тип:** ${data.type || "UNKNOWN"}\n\n`;

  if (Array.isArray(data.answers)) {
    markdown += `**Варіанти:**\n\n`;
    data.answers.forEach((answer, i) => {
      const isCorrect = Array.isArray(data.correctAnswerIndices) && data.correctAnswerIndices.includes(i);
      markdown += `${i + 1}. ${answer}${isCorrect ? " ✅" : ""}\n`;
    });
    markdown += `\n`;
  }

  if (data.explanation) {
    markdown += `**Пояснення:** ${data.explanation}\n\n`;
  }

  if (Array.isArray(data.topics)) {
    markdown += `**Теми:** ${data.topics.join(", ")}\n\n`;
  }

  markdown += `---\n\n`;
});

const title = quiz.quizTitle || $("Parse Generate Options").item.json.topic || "noesis_quiz";
const fileName = `${safeFileName(title)}.md`;

return [
  {
    json: {
      ok: true,
      mode: "quiz",
      quizTitle: quiz.quizTitle || title,
      fileName,
      documentText: markdown,
      telegramChatId: $("Parse Generate Options").item.json.telegramChatId,
      quiz
    },
    binary: {
      data: {
        data: Buffer.from(markdown, "utf8").toString("base64"),
        mimeType: "text/markdown",
        fileName
      }
    }
  }
];

const input = $input.first().json;
const quiz = input.quiz;

if (!quiz || !Array.isArray(quiz.questions)) {
  return [
    {
      json: {
        valid: false,
        error: "Немає quiz.questions для запису в БД."
      }
    }
  ];
}

const options = $("Parse Generate Options").item.json;

return quiz.questions.map((question, index) => {
  const normalized = {
    categoryId: question.categoryId || quiz.categoryId || options.categoryId,
    levelId: String(question.levelId || quiz.levelId || options.levelId),
    num: question.num || index + 1,
    block: question.block || quiz.block || options.block,
    slug: question.slug || `quiz-question-${index + 1}`,
    data: question.data || question
  };

  return {
    json: {
      message: {
        text: JSON.stringify(normalized),
        chat: {
          id: options.telegramChatId
        },
        from: {
          id: options.telegramFromId
        },
        message_id: options.originalTelegramMessageId
      },
      generationOptions: {
        saveToDb: true,
        sendDocument: options.sendDocument,
        format: options.format,
        mode: "quiz",
        topic: options.topic,
        quizTitle: quiz.quizTitle || options.topic
      }
    }
  };
});

function slugify(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .replace(/ї/g, "i")
    .replace(/і/g, "i")
    .replace(/є/g, "e")
    .replace(/ґ/g, "g")
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 60);
}

function randomId(length = 4) {
  const chars = "abcdefghijklmnopqrstuvwxyz0123456789";
  let result = "";

  for (let i = 0; i < length; i++) {
    result += chars[Math.floor(Math.random() * chars.length)];
  }

  return result;
}

function formatAnswerPreview(data) {
  if (Array.isArray(data.answers)) {
    return data.answers
      .map((answer, index) => {
        const isCorrect =
          Array.isArray(data.correctAnswerIndices) &&
          data.correctAnswerIndices.includes(index);

        return `${index + 1}. ${answer}${isCorrect ? " ✅" : ""}`;
      })
      .join("\n");
  }

  if (data.type === "TRUE_FALSE") {
    return `Правильна відповідь: ${data.correctAnswer ? "Так" : "Ні"}`;
  }

  if (Array.isArray(data.correctAnswers)) {
    return `Правильні відповіді: ${data.correctAnswers.join(", ")}`;
  }

  return "Для цього типу питання короткий preview ще не налаштований.";
}

function fail(input, message) {
  return {
    json: {
      valid: false,
      error: message,
      generationOptions: input.generationOptions || null,
      telegramChatId: input.message?.chat?.id,
      originalInput: input
    }
  };
}

function parseOne(input) {
  const messageText = input.message?.text;

  if (!messageText) {
    return fail(input, "Немає message.text з JSON питання.");
  }

  let payload;

  try {
    payload = JSON.parse(messageText);
  } catch (error) {
    return fail(input, "message.text не є валідним JSON.");
  }

  const allowedCategories = [
    "erudite",
    "science",
    "philosophy",
    "culture",
    "noesis",
    "agora"
  ];

  const allowedTypes = [
    "SINGLE_CHOICE",
    "MULTIPLE_CHOICE",
    "TRUE_FALSE",
    "SEQUENCE",
    "MATCHING",
    "COMPARISON",
    "TEXT_INPUT",
    "FILL_IN_THE_BLANK",
    "IMAGE_CHOICE",
    "READING_COMPREHENSION",
    "SLIDER_SCALE",
    "TEN_FACTS"
  ];

  const categoryId = payload.categoryId;
  const levelId = String(payload.levelId || "");
  const num = Number(payload.num);
  const block = String(payload.block || "").toUpperCase();
  const rawSlug = payload.slug;
  const data = payload.data;

  if (!allowedCategories.includes(categoryId)) {
    return fail(input, "Невалідний categoryId.");
  }

  if (!levelId) {
    return fail(input, "Відсутнє поле levelId.");
  }

  if (!Number.isInteger(num) || num < 1 || num > 999) {
    return fail(input, "Поле num має бути цілим числом від 1 до 999.");
  }

  if (!/^[A-Z]$/.test(block)) {
    return fail(input, "Поле block має бути однією великою літерою.");
  }

  if (!data || typeof data !== "object") {
    return fail(input, "Відсутній об'єкт data.");
  }

  if (data.lang !== "ua") {
    return fail(input, "Поле data.lang має бути ua.");
  }

  if (!allowedTypes.includes(data.type)) {
    return fail(input, "Невалідний type.");
  }

  if (!Array.isArray(data.topics) || data.topics.length === 0) {
    return fail(input, "Поле data.topics є обов'язковим.");
  }

  if (!data.question && !["READING_COMPREHENSION", "SLIDER_SCALE"].includes(data.type)) {
    return fail(input, "Поле data.question є обов'язковим для цього типу питання.");
  }

  if (data.type === "SINGLE_CHOICE") {
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail(input, "SINGLE_CHOICE повинен мати рівно 6 варіантів answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== 1) {
      return fail(input, "SINGLE_CHOICE повинен мати один correctAnswerIndices.");
    }
  }

  if (data.type === "MULTIPLE_CHOICE") {
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail(input, "MULTIPLE_CHOICE повинен мати рівно 6 варіантів answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length < 2) {
      return fail(input, "MULTIPLE_CHOICE повинен мати щонайменше два правильні індекси.");
    }
  }

  if (data.type === "TRUE_FALSE" && typeof data.correctAnswer !== "boolean") {
    return fail(input, "TRUE_FALSE повинен мати correctAnswer типу boolean.");
  }

  const numPart = String(num).padStart(2, "0");
  const slug = slugify(rawSlug || data.question || data.type);
  const questionId = `${data.lang}--${numPart}--${block}--${slug}--${randomId()}`;
  const now = new Date().toISOString();

  const documentData = {
    ...data,
    categoryId,
    levelId,
    questionId,
    num,
    block,
    slug,
    status: "pending_review",
    source: "telegram-n8n-ai-quiz",
    createdAt: now,
    updatedAt: now
  };

  const previewText = [
    "🧠 Нове питання на модерацію",
    "",
    `Категорія: ${categoryId}`,
    `Рівень: ${levelId}`,
    `Блок: ${block}`,
    `Тип: ${data.type}`,
    `ID: ${questionId}`,
    `Теми: ${data.topics.join(", ")}`,
    "",
    "Питання:",
    data.question || data.text || "Без короткого тексту питання",
    "",
    "Варіанти / відповідь:",
    formatAnswerPreview(data),
    "",
    data.explanation ? `Пояснення:\n${data.explanation}` : "Пояснення: не додано",
    "",
    "Дія:",
    "✅ записати в БД",
    "❌ відхилити",
    "✏️ переробити"
  ].join("\n");

  return {
    json: {
      valid: true,
      categoryId,
      levelId,
      questionId,
      collectionPath: `${categoryId}/${levelId}/questions`,
      levelDocumentPath: `${categoryId}/${levelId}`,
      pendingCollectionPath: "pendingQuestions",
      documentData,
      previewText,
      telegramChatId: input.message.chat.id,
      telegramFromId: input.message.from.id,
      originalTelegramMessageId: input.message.message_id,
      generationOptions: input.generationOptions || null
    }
  };
}

return $input.all().map(item => parseOne(item.json));

const pending = $input.item.json;

const now = new Date().toISOString();

return [
  {
    json: {
      ...pending,
      status: "rejected",
      rejectedAt: now,
      updatedAt: now
    }
  }
];

const pending = $input.item.json;
const now = new Date().toISOString();

return [
  {
    json: {
      ...pending,
      status: "needs_revision",
      revisionRequestedAt: now,
      updatedAt: now,
      revisionInstructionMessage: [
        "✏️ Питання позначено як таке, що потребує переробки.",
        "",
        `ID: ${pending.questionId}`,
        "",
        "Напиши відповіддю на це повідомлення, що саме потрібно виправити.",
        "",
        "Приклади:",
        "- зроби варіанти менш очевидними",
        "- додай точніше пояснення",
        "- зроби питання складнішим",
        "- заміни тему або формулювання"
      ].join("\n")
    }
  }
];

const input = $input.first().json;
const message = input.message || {};

const revisionComment = String(message.text || "").trim();

const replyText = String(
  message.reply_to_message?.text ||
  message.reply_to_message?.caption ||
  ""
).trim();

const telegramChatId = message.chat?.id;
const telegramFromId = message.from?.id;
const replyMessageId = message.message_id;
const repliedToMessageId = message.reply_to_message?.message_id;

function extractQuestionId(text) {
  const source = String(text || "")
    .replace(/[–—]/g, "-")
    .replace(/\u00A0/g, " ");

  const lines = source.split(/\r?\n/).map(line => line.trim());

  for (const line of lines) {
    const match = line.match(/^ID:\s*(.+)$/i);
    if (match && match[1]) {
      return match[1].trim().split(/\s+/)[0];
    }
  }

  const fallback = source.match(/ua--[A-Za-z0-9_-]+/);
  if (fallback) {
    return fallback[0].trim();
  }

  return "";
}

if (!message.reply_to_message) {
  return [
    {
      json: {
        ok: false,
        error: "Повідомлення не є відповіддю на запит переробки. Натисни Reply саме на повідомлення бота з ID питання.",
        telegramChatId,
        debugReplyText: replyText,
        debugInput: input
      }
    }
  ];
}

const questionId = extractQuestionId(replyText);

if (!questionId) {
  return [
    {
      json: {
        ok: false,
        error: "Не вдалося знайти ID питання в повідомленні, на яке дана відповідь.",
        telegramChatId,
        debugReplyText: replyText,
        debugInput: input
      }
    }
  ];
}

if (!revisionComment) {
  return [
    {
      json: {
        ok: false,
        error: "Коментар для переробки порожній.",
        telegramChatId,
        questionId,
        debugReplyText: replyText
      }
    }
  ];
}

return [
  {
    json: {
      ok: true,
      questionId,
      revisionComment,
      telegramChatId,
      telegramFromId,
      revisionReplyMessageId: replyMessageId,
      repliedToMessageId,
      receivedAt: new Date().toISOString(),
      debugReplyText: replyText
    }
  }
];

const pending = $input.item.json;

const revision = $("Parse Revision Reply").item.json;

const now = new Date().toISOString();

const revisionHistory = Array.isArray(pending.revisionHistory)
  ? pending.revisionHistory
  : [];

revisionHistory.push({
  comment: revision.revisionComment,
  receivedAt: revision.receivedAt,
  replyMessageId: revision.revisionReplyMessageId
});

return [
  {
    json: {
      ...pending,
      status: "revision_comment_received",
      revisionComment: revision.revisionComment,
      revisionHistory,
      updatedAt: now,
      telegramChatId: revision.telegramChatId
    }
  }
];

const input = $input.first().json;

const aiText =
  input.output_text ||
  input.output?.[0]?.content?.[0]?.text ||
  input.output?.[0]?.content?.find?.(c => c.type === "output_text")?.text ||
  input.text ||
  "";

if (!aiText) {
  return [
    {
      json: {
        message: { text: "" },
        aiError: "OpenAI не повернув текст у відомому полі.",
        raw: input
      }
    }
  ];
}

const cleaned = String(aiText)
  .trim()
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```$/i, "")
  .trim();

const revision = $("Prepare Revision Comment").item.json;

return [
  {
    json: {
      message: {
        text: cleaned,
        chat: {
          id: revision.telegramChatId
        },
        from: {
          id: revision.telegramFromId || 59229320
        },
        message_id: revision.revisionReplyMessageId || revision.originalTelegramMessageId
      },
      generationOptions: {
        saveToDb: true,
        sendDocument: false,
        format: "markdown",
        mode: "revision",
        topic: revision.generationOptions?.topic || "revision",
        revisedFrom: revision.questionId,
        revisionComment: revision.revisionComment
      }
    }
  }
];

const pending = $input.item.json;

const documentData = pending.documentData;
const revisionComment = pending.revisionComment;

if (!documentData) {
  return [
    {
      json: {
        ok: false,
        error: "Немає documentData для переробки питання.",
        telegramChatId: pending.telegramChatId
      }
    }
  ];
}

if (!revisionComment) {
  return [
    {
      json: {
        ok: false,
        error: "Немає revisionComment для переробки питання.",
        telegramChatId: pending.telegramChatId
      }
    }
  ];
}

const prompt = [
  "Ти редактор питань для освітнього застосунку NoesisQuiz.",
  "",
  "Є старе питання у JSON і коментар людини, що саме потрібно змінити.",
  "",
  "Завдання: перепиши питання відповідно до коментаря, але збережи формат NoesisQuiz.",
  "",
  "Поверни тільки валідний JSON без Markdown і без пояснень поза JSON.",
  "",
  "Коментар людини:",
  revisionComment,
  "",
  "Старе питання documentData:",
  JSON.stringify(documentData, null, 2),
  "",
  "Поверни JSON верхнього рівня такого формату:",
  JSON.stringify(
    {
      categoryId: documentData.categoryId,
      levelId: String(documentData.levelId),
      num: documentData.num,
      block: documentData.block,
      slug: `${documentData.slug || "revised-question"}-revised`,
      data: {
        lang: "ua",
        type: documentData.type,
        question: "...",
        answers: ["...", "...", "...", "...", "...", "..."],
        correctAnswerIndices: [0],
        explanation: "...",
        topics: documentData.topics || [],
        scientificDisciplines: documentData.scientificDisciplines || [],
        recommendedLiterature: [],
        revisedFrom: pending.questionId
      }
    },
    null,
    2
  ),
  "",
  "Правила:",
  "- Виконай саме коментар людини.",
  "- Не змінюй categoryId, levelId, block і num без потреби.",
  "- Якщо type = SINGLE_CHOICE, має бути рівно 6 варіантів answers.",
  "- Неправильні варіанти мають бути правдоподібними, але неправильними.",
  "- Пояснення має відповідати новому формулюванню.",
  "- Не вигадуй джерела. Якщо джерело не впевнене, recommendedLiterature залиш []."
].join("\n");

return [
  {
    json: {
      ...pending,
      openAiRevisionBody: {
        model: "gpt-4.1-mini",
        input: prompt
      }
    }
  }
];

const newQuestion = $input.item.json;
const revisionSource = $("Prepare Revision Comment").item.json;
const now = new Date().toISOString();

return [
  {
    json: {
      questionId: revisionSource.questionId,
      status: "revised",
      revisedAt: now,
      revisedQuestionId: newQuestion.questionId,
      revisionComment: revisionSource.revisionComment,
      updatedAt: now,

      targetCollectionPath: revisionSource.targetCollectionPath,
      targetLevelDocumentPath: revisionSource.targetLevelDocumentPath,
      documentData: revisionSource.documentData,
      previewText: revisionSource.previewText,
      telegramChatId: revisionSource.telegramChatId,
      originalTelegramMessageId: revisionSource.originalTelegramMessageId,
      generationOptions: revisionSource.generationOptions || null,
      createdAt: revisionSource.createdAt,
      revisionRequestedAt: revisionSource.revisionRequestedAt,
      revisionHistory: revisionSource.revisionHistory || []
    }
  }
];

